216:     boolean handleCorruption(final Set<TaskId> corruptedTasks) {
217:         final Set<TaskId> activeTasks = new HashSet<>(tasks.activeTaskIds());
218: 
219:         // We need to stop all processing, since we need to commit non-corrupted tasks as well.
220:         maybeLockTasks(activeTasks);
221: 
222:         final Set<Task> corruptedActiveTasks = new HashSet<>();
223:         final Set<Task> corruptedStandbyTasks = new HashSet<>();
224: 
225:         for (final TaskId taskId : corruptedTasks) {
226:             final Task task = tasks.task(taskId);
227:             if (task.isActive()) {
228:                 corruptedActiveTasks.add(task);
229:             } else {
230:                 corruptedStandbyTasks.add(task);
231:             }
232:         }
233: 
234:         // Make sure to clean up any corrupted standby tasks in their entirety before committing
235:         // since TaskMigrated can be thrown and the resulting handleLostAll will only clean up active tasks
236:         closeDirtyAndRevive(corruptedStandbyTasks, true);
237: 
238:         // We need to commit before closing the corrupted active tasks since this will force the ongoing txn to abort
239:         try {
240:             final Collection<Task> tasksToCommit = tasks.allTasksPerId()
241:                 .values()
242:                 .stream()
243:                 .filter(t -> t.state() == Task.State.RUNNING)
244:                 .filter(t -> !corruptedTasks.contains(t.id()))
245:                 .collect(Collectors.toSet());
246:             commitTasksAndMaybeUpdateCommittableOffsets(tasksToCommit, new HashMap<>());
247:         } catch (final TaskCorruptedException e) {
248:             log.info("Some additional tasks were found corrupted while trying to commit, these will be added to the " +
249:                          "tasks to clean and revive: {}", e.corruptedTasks());
250:             corruptedActiveTasks.addAll(tasks.tasks(e.corruptedTasks()));
251:         } catch (final TimeoutException e) {
252:             log.info("Hit TimeoutException when committing all non-corrupted tasks, these will be closed and revived");
253:             final Collection<Task> uncorruptedTasks = new HashSet<>(tasks.activeTasks());
254:             uncorruptedTasks.removeAll(corruptedActiveTasks);
255:             // Those tasks which just timed out can just be closed dirty without marking changelogs as corrupted
256:             closeDirtyAndRevive(uncorruptedTasks, false);
257:         }
258: 
259:         closeDirtyAndRevive(corruptedActiveTasks, true);
260: 
261:         maybeUnlockTasks(activeTasks);
262: 
263:         return !corruptedActiveTasks.isEmpty();
264:     }
