266:     private void closeDirtyAndRevive(final Collection<Task> taskWithChangelogs, final boolean markAsCorrupted) {
267:         for (final Task task : taskWithChangelogs) {
268:             if (task.state() != State.CLOSED) {
269:                 final Collection<TopicPartition> corruptedPartitions = task.changelogPartitions();
270: 
271:                 // mark corrupted partitions to not be checkpointed, and then close the task as dirty
272:                 // TODO: this step should be removed as we complete migrating to state updater
273:                 if (markAsCorrupted && stateUpdater == null) {
274:                     task.markChangelogAsCorrupted(corruptedPartitions);
275:                 }
276: 
277:                 try {
278:                     // we do not need to take the returned offsets since we are not going to commit anyways;
279:                     // this call is only used for active tasks to flush the cache before suspending and
280:                     // closing the topology
281:                     task.prepareCommit(false);
282:                 } catch (final RuntimeException swallow) {
283:                     log.warn("Error flushing cache for corrupted task {}. " +
284:                         "Since the task is closing dirty, the following exception is swallowed: {}",
285:                         task.id(), swallow.getMessage());
286:                 }
287: 
288:                 try {
289:                     task.suspend();
290: 
291:                     // we need to enforce a checkpoint that removes the corrupted partitions
292:                     if (markAsCorrupted) {
293:                         task.postCommit(true);
294:                     }
295:                 } catch (final RuntimeException swallow) {
296:                     log.warn("Error suspending corrupted task {}. " +
297:                         "Since the task is closing dirty, the following exception is swallowed: {}",
298:                         task.id(), swallow.getMessage());
299:                 }
300:                 task.closeDirty();
301:             }
302:             // For active tasks pause their input partitions so we won't poll any more records
303:             // for this task until it has been re-initialized;
304:             // Note, closeDirty already clears the partition-group for the task.
305:             if (task.isActive()) {
306:                 final Set<TopicPartition> currentAssignment = mainConsumer.assignment();
307:                 final Set<TopicPartition> taskInputPartitions = task.inputPartitions();
308:                 final Set<TopicPartition> assignedToPauseAndReset =
309:                     intersection(HashSet::new, currentAssignment, taskInputPartitions);
310:                 if (!assignedToPauseAndReset.equals(taskInputPartitions)) {
311:                     log.warn(
312:                         "Expected the current consumer assignment {} to contain the input partitions {}. " +
313:                             "Will proceed to recover.",
314:                         currentAssignment,
315:                         taskInputPartitions
316:                     );
317:                 }
318: 
319:                 task.addPartitionsForOffsetReset(assignedToPauseAndReset);
320:             }
321:             if (stateUpdater != null) {
322:                 tasks.removeTask(task);
323:             }
324:             task.revive();
325:             if (stateUpdater != null) {
326:                 tasks.addPendingTasksToInit(Collections.singleton(task));
327:             }
328:         }
329:     }
